pens <- tibble::tibble(
  year = c(2024, 2023, 2022, 2021, 2020, 2019),
  yards_per_game = c(64.0, 66.3, 55.1, 69.2, 67.6, 53.9),
  rank = c(114, 125, 75, 118, 109, 70),
  teams = c(134, 133, 131, 130, 127, 130)
)

# Calculate percentile using dplyr (lower rank = worse = lower percentile)
pen_data <- pens |>
  dplyr::mutate(
    percentile = round((teams - rank) / teams * 100, 1)
  )


