### Elevator plot


::: {.cell}

```{.r .cell-code}
coaching_records <- data.frame(
  Coach = c("Carl Torbush\n(1997-2000)", "John Bunting\n(2001-2006)", "Butch Davis\n(2007-2010)", 
            "Everett Withers\n(2011)", "Larry Fedora\n(2011-2018)", "Mack Brown 2.0\n(2019-2024)"),
  Record = c("17-18\n.486", "27-45\n.375", "28-23\n.549", "7-6\n.538", "45-43\n.511", "44-33\n.571"),
  stringsAsFactors = FALSE
)

main_plot <- unc_fball |>
  dplyr::filter(Year > 1998) |> 
  ggplot2::ggplot(ggplot2::aes(y = Year)) +
  ggplot2::geom_vline(xintercept = c(0, 12), color = "gray40", size = 1.5, alpha = 0.7) +
  ggplot2::geom_segment(ggplot2::aes(x = pmin(W, L), xend = pmax(W, L), yend = Year), 
                        color = "gray60", size = 1) +
  ggplot2::geom_point(ggplot2::aes(x = W), color = "#56a0d3", size = 3, shape = 15) +
  ggplot2::geom_point(ggplot2::aes(x = L), color = "#F08080", size = 3, shape = 15) +
  ggplot2::scale_y_continuous(breaks = seq(1999, 2024, 1), limits = c(1998.5, 2030), labels = function(x) paste0("'", sprintf("%02d", x %% 100))) +
  ggplot2::scale_x_continuous(breaks = seq(0, 12, 1), 
                              limits = c(0, 12)) +
  ggplot2::labs(
    title = "Carolina football is trapped in an elevator of mediocrity<br>
    <span style='color: #56a0d3;'>Ups (wins)</span> and 
    <span style='color:#F08080;'>downs (losses)</span> over past 25 years",
    subtitle = "UNC is 160-164 over the past 25 seasons<br> 
    An average of 6.2 wins and 6.3 losses over six <em>different</em> head coaches.",
    x = "# of Wins or Losses",
    y = "",
    caption = "data via sportsreference.com | Viz by Chris at Bless your Chart"
  ) +
  ggplot2::coord_flip() +
  hrbrthemes::theme_ipsum_rc() +
  ggplot2::theme(
    plot.title = ggtext::element_markdown(family = "Roboto Condensed"),
    plot.subtitle = ggtext::element_markdown(family = "Roboto Condensed"),
    axis.title = ggplot2::element_text(family = "Roboto Condensed"),
    axis.text = ggplot2::element_text(family = "Roboto Condensed"),
    axis.text.x = ggplot2::element_text(angle = 35, hjust = 1, size = 8)
  ) +
  ggplot2::annotate(
    cfbplotR::GeomCFBlogo,
    y = 2028,   
    x = 10.5,           
    team = "North Carolina",
    height = 0.09
  ) +
  ggplot2::geom_hline(yintercept = c(2000.5, 2006.5, 2010.5, 2011.5,
                                     2018.5, 2024.5),
                      linetype = "dotted", color = "gray60") +
  ggplot2::annotation_custom(
    grob = gridExtra::tableGrob(
      coaching_records,
      rows = NULL,
      theme = gridExtra::ttheme_minimal(
        core = list(
          fg_params = list(fontfamily = "Roboto Condensed", fontsize = 6.5),
          bg_params = list(fill = c("white", "gray95"), alpha = 0.8)
        ),
        colhead = list(
          fg_params = list(fontfamily = "Roboto Condensed", fontsize = 7.5, 
                           fontface = "bold"),
          bg_params = list(fill = "#56a0d3", alpha = 0.3)
        )
      )
    ),
    ymin = 2027, ymax = 2029.5, xmin = 3, xmax = 10.5  # Positioned under the logo
  )

ggplot2::ggsave(
  "el_plot.png",
  main_plot,
  w =8,
  h = 8,
  dpi = 600,
  type = 'cairo',
  bg = "white"
)

