custom_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/ncaa/500/153.png'
       style='height: 55px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>North Carolina's penalty yards per game since 2019</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Shows the team's ranking and percentile in penalty yards per game since the 2019 season.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png' 
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)

pen_tbl <- pen_data |> 
  dplyr::mutate(
    rank_teams = paste0(rank, " out of ", teams)
  ) |> 
  dplyr::select(
    year, yards_per_game, percentile, rank_teams
  ) |> 
  gt::gt() |>
  gtUtils::gt_theme_gtutils() |> 
  gtExtras::gt_merge_stack(
    col1 = yards_per_game,
    col2 = rank_teams,
        palette = c("black", "#333333")
  ) |> 
  gtUtils::gt_column_subheaders(
    year = list(heading = "Season", subtitle = "Year"),
    yards_per_game = list(heading = "Yards per Game", subtitle = "# of out FBS teams"),
    percentile = list(heading = "Percentile", subtitle = "Out of FBS teams"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |> 
    gtUtils::gt_border_grid(color = "black",
                          weight = 1,
                          include_labels = FALSE) |> 
  gtExtras::gt_add_divider(
    columns = c(year),
    sides = "right",
    color = "black"
  ) |> 
  gtUtils::gt_color_pills(percentile, format = "percent", scale_percent = FALSE, domain = c(0,100),
                          digits = 1) |> 
  gt::tab_header(title = gt::html(custom_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via cfbstats.com | theme via {gtUtils} <br>
        <hr><b>Table by Chris at Bless your chart</b>"
      )
  ) |>
    gtUtils::gt_border_bars_bottom(c("#56a0d3", "#89BDE0", "#BBD9ED")) |> 
  gt::tab_options(table.width = gt::px(475)) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |> 
  gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative"),
                    size = gt::px(14)
      )
    ),
    locations = gt::cells_body(
      rows = gt::everything(),
      columns = gt::everything()
    )
  )


gt_save_crop(
